mapper.select:
SELECT s.solution_id, s.algorithm, s.`type`, s.language, s.code, s.user_problem_id
FROM solutions s
JOIN user_problems up
USING (user_problem_id)
WHERE up.user_id = #{userId}
  AND s.solution_id = #{solutionId}

SELECT COUNT(*)
FROM user_problems
WHERE user_id = #{userId}
  AND user_problem_id = #{userProblemId}

SELECT COUNT(*)
FROM solutions s
JOIN user_problems up
USING (user_problem_id)
WHERE up.user_id = #{userId}
  AND s.user_problem_id = #{userProblemId}

mapper.delete:
DELETE s
FROM solutions s
JOIN user_problems up
USING (user_problem_id)
WHERE up.user_id = #{userId}
  AND s.solution_id = #{solutionId}
